// ============================================================
// Helper: Get ability data by name
function getAbilityData(name) {
  return ABILITIES_DB[name] || null;
}

// Helper: Get keyword data by name
function getKeywordData(name) {
  return KEYWORDS_DB[name] || null;
}

// Helper: Build ability name hyperlink HTML
function abilityLink(name) {
  const ability = ABILITIES_DB[name];
  if (!ability) return name;
  return `<a href="${ability.url}" target="_blank" rel="noopener" class="ability-link">${name}</a>`;
}

// Helper: Build keyword hyperlinks HTML
function keywordLinks(keywords) {
  if (!keywords || keywords.length === 0) return '';
  return keywords.map(kw => {
    const data = KEYWORDS_DB[kw];
    if (data) {
      return `<a href="${data.url}" target="_blank" rel="noopener" class="keyword-link" title="${data.description}">${kw}</a>`;
    }
    return `<span class="keyword-link">${kw}</span>`;
  }).join(', ');
}

// Helper: Build cost string
function abilityCosts(ability) {
  const costs = [];
  if (ability.manaCost) costs.push(`Mana: ${ability.manaCost}`);
  if (ability.apCost) costs.push(`AP: ${ability.apCost}`);
  if (ability.rpCost) costs.push(`RP: ${ability.rpCost}`);
  return costs.join(' | ') || 'No cost';
}